class Thought:
    id, content, score, parents = ...

class GraphOfThoughts:
    def __init__(self, problem):
        self.nodes = {}
        self.root = self.add(content=problem, parents=[])

    def add(self, content, parents):
        t = Thought(id=new_id(), content=content,
                    score=None, parents=parents)
        self.nodes[t.id] = t
        return t

    def generate(self, node, k):
        # CoT-style expansion: produce k child thoughts.
        for c in llm.sample(node.content, n=k):
            self.add(content=c, parents=[node])

    def refine(self, node):
        improved = llm.improve(node.content)
        return self.add(content=improved, parents=[node])

    def aggregate(self, nodes):
        merged = llm.merge([n.content for n in nodes])
        return self.add(content=merged, parents=nodes)

    def score(self, node):
        node.score = llm.score(node.content)

# Orchestrator chains operations to produce the final thought.
g = GraphOfThoughts(problem)
g.generate(g.root, k=5)
candidates = list(g.nodes.values())[1:]
for n in candidates:
    g.score(n)
top = sorted(candidates, key=lambda n: -n.score)[:3]
final = g.aggregate(top)
return final.content

function rest_em(base_model, problems, ground_truth, R, K):
    model = base_model
    for round in 1..R:
        # E-step: generate K responses per problem with the current model.
        accepted = []
        for p in problems:
            for k in 1..K:
                resp = sample(model, p, temperature=0.8)
                # Reward can be exact-match against ground_truth
                # OR an executable test (unit test, code runner).
                if reward(resp, ground_truth[p]) >= THRESHOLD:
                    accepted.append({"prompt": p, "completion": resp})

        if not accepted:
            break   # collapse: model produces nothing reward-able

        # M-step: supervised fine-tune the BASE model on accepted set.
        # (ReST-EM restarts from base each round to avoid drift.)
        model = supervised_finetune(
            base_model=base_model,
            data=accepted,
        )

    return model

SELF_ASK_PROMPT = """Question: {q}
Are follow up questions needed here: Yes.
Follow up:"""

function self_ask(question, search_tool):
    transcript = SELF_ASK_PROMPT.format(q=question)

    for step in 1..MAX_STEPS:
        # Model emits the next follow-up question (or final answer).
        chunk = llm.generate(
            prompt=transcript,
            stop=["Intermediate answer:", "So the final answer is"],
        )
        transcript += chunk

        if "So the final answer is" in chunk:
            return chunk.split("So the final answer is")[-1].strip()

        # Otherwise the chunk ends with a follow-up question.
        followup = chunk.strip().splitlines()[-1]
        intermediate = search_tool(followup)
        transcript += f"\nIntermediate answer: {intermediate}\nFollow up:"

    return abort("step budget exhausted")

function star(base_model, dataset, R):
    model = base_model
    for round in 1..R:
        kept = []

        for (question, gold_answer) in dataset:
            # 1. Generate a rationale + answer with CoT prompting.
            rationale, answer = cot_generate(model, question)

            if answer == gold_answer:
                # Correct: keep the rationale as a training example.
                kept.append({
                    "prompt":     question,
                    "completion": rationale + "\nAnswer: " + answer,
                })
            else:
                # 2. Rationalization: give the gold answer as a hint
                #    and ask the model to produce a rationale that
                #    *would have* justified it.
                hinted = cot_generate_with_hint(
                    model, question, hint=gold_answer,
                )
                kept.append({
                    "prompt":     question,
                    "completion": hinted + "\nAnswer: " + gold_answer,
                })

        # 3. Fine-tune on the kept (correct + rationalized) set.
        model = supervised_finetune(base_model, data=kept)

    return model

function answer_with_scaled_compute(task, budget):
    cls = classify(task)

    if cls == "verifier_amenable":
        # Best-of-N: sample N answers, pick the highest-scoring.
        cands = [llm.sample(task) for _ in range(budget.N)]
        return argmax(cands, key=verifier.score)

    if cls == "sampling_amenable":
        # Self-consistency: sample, then majority-vote the answer.
        cands = [llm.sample(task, temperature=0.7)
                 for _ in range(budget.N)]
        return majority_vote([extract_answer(c) for c in cands])

    if cls == "combinatorial":
        # Tree search over thought steps (see tree-of-thoughts).
        return tree_search(task, width=budget.W, depth=budget.D)

    if cls == "sequential_reasoning":
        # Extended thinking: longer internal CoT budget.
        return llm.generate(
            task, thinking={"budget_tokens": budget.thinking},
        )

    return llm.generate(task)   # default: single pass

function tree_of_thoughts(problem, B=3, K=5, MAX_DEPTH=4):
    root = {"path": [], "state": problem}
    frontier = [root]

    for depth in 1..MAX_DEPTH:
        # 1. Expand: each node proposes K next thoughts.
        children = []
        for node in frontier:
            for thought in llm.sample_thoughts(node, k=K):
                children.append({
                    "path":  node["path"] + [thought],
                    "state": apply(node["state"], thought),
                })

        # 2. Evaluate: self-evaluate each child (or use a programmatic
        #    checker for math / code).
        for c in children:
            c["score"] = llm.evaluate(c["state"])  # e.g. "sure/maybe/no"

        # 3. Prune: keep the top-B by score. Backtracking is implicit
        #    here: low-scoring branches simply drop off the frontier.
        frontier = sorted(children, key=lambda c: -c["score"])[:B]

        if any(is_terminal(c["state"]) for c in frontier):
            break

    best = max(frontier, key=lambda c: c["score"])
    return best["path"], best["state"]
